package com.babidndn.payment; import org.springframework.stereotype.Service;
@Service public class TossPaymentGateway implements PaymentGateway { private final PaymentRepository repository; public TossPaymentGateway(PaymentRepository repository){this.repository=repository;} public Payment request(PaymentRequest request){ return repository.save(new Payment(request.method(),request.amount(),PaymentStatus.READY,request.pgTransactionId())); } public Payment confirm(PaymentRequest request){ return repository.save(new Payment(request.method(),request.amount(),PaymentStatus.COMPLETED,request.pgTransactionId())); } }
